12	/**
13	 * 集成测试：sdfSign — 随单返签约
14	 *
15	 * 接口：AdAccountService#sdfSign(SdfSignReq)
16	 *
17	 * 新增字段：
18	 *   - cashRatio (String): 商家在签约页选择的转入比例（仅 CUSTOM 自定义档位时有效）
19	 *
20	 * 签约时比例匹配逻辑（按 ratioMode 分支）：
21	 *   FIXED (0/null)  → 使用 activity.cash_ratio，忽略 req.cashRatio
22	 *   DYNAMIC (1)     → 查 wm_ad_sdf_ratio_config_future (status=1) 最新记录；无则用 activity.cash_ratio
23	 *   CUSTOM (2)      → req.cashRatio 非 null 时校验范围 max(1%, x-y%) ~ 50%；为 null 时查 status=1 最新；仍无则用 activity.cash_ratio
24	 *
25	 * 测试维度：
26	 *   TC01 - FIXED 模式，不传 cashRatio：使用 activity.cash_ratio
27	 *   TC02 - FIXED 模式，传 cashRatio：忽略 cashRatio，仍使用 activity.cash_ratio
28	 *   TC03 - DYNAMIC 模式，有 status=1 配置：使用配置比例
29	 *   TC04 - DYNAMIC 模式，无 status=1 配置：fallback 到 activity.cash_ratio
30	 *   TC05 - CUSTOM 模式，cashRatio 在范围内（如 "29.5"）：签约成功，立即生效
31	 *   TC06 - CUSTOM 模式，cashRatio 低于下限：返回错误
32	 *   TC07 - CUSTOM 模式，cashRatio 高于 50%：返回错误
33	 *   TC08 - CUSTOM 模式，cashRatio=null，有 status=1 配置：使用配置比例
34	 *   TC09 - CUSTOM 模式，cashRatio=null，无配置：fallback 到 activity.cash_ratio
35	 *   TC10 - 重复签约：幂等处理
36	 */
37	public class SdfSignTest extends SdfIntegrationBaseTest {
38	
39	    // ============================================================
