45	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_FIXED, TEST_ACTIVITY_ID_FIXED, null);
46	
47	        // when
48	        Result result = adAccountService.sdfSign(req);
49	
50	        // then
51	        assertNotNull(result);
52	        assertTrue("FIXED 模式签约应成功", result.isSuccess());
53	        // verify DB: wm_ad_sdf_sign.cash_ratio_decimal=30
54	        // TODO: verifySignCashRatio(TEST_PARTNER_ID_FIXED, "30");
55	    }
