187	
188	        // then
189	        assertNotNull(result);
190	        assertTrue("CUSTOM 模式 cashRatio=null 无配置应 fallback 到 activity.cash_ratio 成功", result.isSuccess());
191	        // verify DB: cash_ratio_decimal=activity.cash_ratio
192	    }
