195	    // TC10: 重复签约（幂等）
196	    // ============================================================
197	    @Test
198	    public void tc10_duplicateSign_idempotent() {
199	        // given: 已签约
200	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_FIXED_SIGNED, TEST_ACTIVITY_ID_FIXED, null);
201	
202	        // when
203	        Result result = adAccountService.sdfSign(req);
204	
205	        // then
206	        assertNotNull(result);
207	        // 幂等：成功或返回已签约提示，不抛异常
208	        // TODO: 根据实际业务逻辑确认是 success 还是特定错误码
209	    }
210	
211	    // ============================================================
212	    // Helpers
213	    // ============================================================
214	    private SdfSignReq buildSignReq(long partnerId, long activityId, String cashRatio) {
215	        SdfSignReq req = new SdfSignReq();
