217	        req.setPartnerType(PARTNER_TYPE_POI);
218	        req.setActivityId(activityId);
219	        req.setOperateType(OPERATE_TYPE_SIGN);
220	        req.setCashRatio(cashRatio);
221	        return req;
222	    }
223	}
