50	
51	        // then
52	        assertNotNull(result);
53	        assertTrue("已签约门店整数比例应成功", result.isSuccess());
54	        // verify DB: wm_ad_sdf_ratio_config_future INSERT, status=0, cash_ratio=30, effective_date=tomorrow
55	        // TODO: verifySdfRatioConfigFutureInserted(TEST_PARTNER_ID_DYNAMIC_SIGNED, "30", 0);
